export function getPrayerCategories(): PrayerCategory[] {
  return PRAYER_CATEGORIES;
}

export function getPrayerById(categoryId: string, prayerId: string): Prayer | undefined {
  const category = PRAYER_CATEGORIES.find(cat => cat.id === categoryId);
  return category?.prayers.find(prayer => prayer.id === prayerId);
}

export function getAllPrayers(): Prayer[] {
  return PRAYER_CATEGORIES.flatMap(category => category.prayers);
}